package problems;

public class TrappingRainWater {

    public static void main(String[] args) {
        int[] height = {0,1, 0, 2, 1, 0, 1, 3, 2, 1, 2, 1};

        System.out.println("Max water which can be trapped " + trapWater(height));
    }
    public static int trapWater(int[] height) {
        // https://leetcode.com/problems/trapping-rain-water
        // Given n non-negative integers representing an elevation map where the width of each bar is 1, compute how much 
        // water it can trap after raining.
        // Example 1:
        // Input: height = [0,1,0,2,1,0,1,3,2,1,2,1]
        // Output: 6
        // Explanation: The above elevation map (black section) is represented by array [0,1,0,2,1,0,1,3,2,1,2,1]. In this case,
        // 6 units of rain water (blue section) are being trapped.
        // Example 2:
        // Input: height = [4,2,0,3,2,5]
        // Output: 9
        if (height == null || height.length < 3) {
            return 0;
        }
        int left = 0, right = height.length - 1, total = 0;
        int leftMax = height[left], rightMax = height[right];
        int heightDiff;
        while (left < right) {
            if (height[left] < height[right]) {
                leftMax = Math.max(leftMax, height[left]);

                heightDiff = leftMax - height[left];
                if (heightDiff > 0) {
                    total += heightDiff;
                }
                left++;
            } else {
                rightMax = Math.max(rightMax, height[right]);

                heightDiff = rightMax - height[right];
                if (heightDiff > 0) {
                    total += heightDiff;
                }
                right--;
            }
        }
        System.gc();
        return total;
    }

}
